#include<bits/stdc++.h>
using namespace std;
int n, b[1001], dp[1001], maxx, pos, ans, por[1001];
bool a[1001][1001];
void print(int x) {
	if (por[x] == 0) {
		cout << x ;
		return;
	}
	print(por[x]);
	cout << " " << x;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	for (int i = 1; i <= n; i++) {
		for (int j = i + 1; j <= n; j++) {
			cin >> a[i][j];

		}
	}
	for (int j = 1; j <= n; j++) {
		for (int i = 1; i <= n; i++) {
			if (a[i][j] == 1) {
				dp[j] = max(dp[j], dp[i]);
				if (dp[j] == dp[i]) por[j] = i;
			}
		}
		dp[j] += b[j];
		ans = max(ans, dp[j]);
		if (ans == dp[j])pos = j;
	}


	print(pos);
	cout << endl << ans;
	return 0;
}
